以下是使用 C++ 实现事件时间轴的示例代码：

```cpp
#include <iostream>
#include <map>
#include <vector>
#include <chrono>
#include <thread>
#include <algorithm>

// 定义事件类型
enum EventType {
    EVENT_TYPE_A,
    EVENT_TYPE_B,
    EVENT_TYPE_C,
};

// 定义事件结构体
struct Event {
    EventType type;
    std::string data;
    Event(EventType t, const std::string& d) : type(t), data(d) {}
};

// 定义事件处理函数类型
using EventHandler = std::function<void(const Event&)>;

// 定义时间轴类
class TimeLine {
public:
    TimeLine() : currentTime_(0) {}

    // 注册事件
    void RegisterEvent(int time, EventType type, const std::string& data) {
        events_[time].push_back(Event(type, data));
    }

    // 设置时间轴时间
    void SetTime(int time) {
        if (time < currentTime_) {
            // 时间轴倒退时清空前面的事件
            for (auto it = events_.begin(); it != events_.end();) {
                if (it->first < time) {
                    it = events_.erase(it);
                } else {
                    break;
                }
            }
        }

        currentTime_ = time;
        auto it = events_.find(currentTime_);
        if (it != events_.end()) {
            // 触发当前时刻的所有事件
            for (auto& event : it->second) {
                auto handlerIt = eventHandlers_.find(event.type);
                if (handlerIt != eventHandlers_.end()) {
                    handlerIt->second(event);
                }
            }
        }
    }

    // 注册事件处理函数
    void RegisterEventHandler(EventType type, EventHandler handler) {
        eventHandlers_[type] = handler;
    }

private:
    int currentTime_;
    std::map<int, std::vector<Event>> events_;
    std::map<EventType, EventHandler> eventHandlers_;
};

// 示例：打印事件处理结果
void PrintEventHandler(const Event& event) {
    std::cout << "Event type: " << event.type << ", data: " << event.data << std::endl;
}

int main() {
    // 创建时间轴
    TimeLine timeLine;

    // 注册事件处理函数
    timeLine.RegisterEventHandler(EVENT_TYPE_A, PrintEventHandler);
    timeLine.RegisterEventHandler(EVENT_TYPE_B, PrintEventHandler);
    timeLine.RegisterEventHandler(EVENT_TYPE_C, PrintEventHandler);

    // 注册事件
    timeLine.RegisterEvent(1, EVENT_TYPE_A, "event A at time 1");
    timeLine.RegisterEvent(2, EVENT_TYPE_B, "event B at time 2");
    timeLine.RegisterEvent(3, EVENT_TYPE_C, "event C at time 3");
    timeLine.RegisterEvent(3, EVENT_TYPE_A, "event A2 at time 3");

    // 执行时间轴
    for (int i = 1; i <= 3; ++i) {
        timeLine.SetTime(i);
        std::this_thread::sleep_for(std::chrono::seconds(1));
    }

    // 反向执行时间轴
    for (int i = 3; i >= 1; --i) {
        timeLine.SetTime(i);
        std::this_thread::sleep_for(std::chrono::seconds(1));
    }

    return 0;
}
```

该示例代码实现了事件时间轴的基本功能：注册事件、注册事件处理函数、设置时间轴时间，并在时间轴时间变化时触发对应时刻的事件。同时，还实现了时间轴倒退时清空前面的事件的功能。

在此示例代码中，事件和事件处理函数均使用了枚举类型，方便进行类型判断和处理。同时，使用了函数指针类型 `EventHandler` 来定义事件处理函数类型，可方便地在多个函数之间传递和调用。

另外，为了演示时间轴的使用效果，示例代码在设置时间轴时间时使用了 `std::this_thread::sleep_for` 函数来模拟时间的流逝。在实际使用中，应根据具体需求来决定如何设置时间轴时间。

如果需要将时间轴刻度精确到毫秒，可以使用 std::chrono 库来实现。

在时间轴类中，可以将时间戳从 int 类型改为 std::chrono::milliseconds 类型，并在设置时间轴时间时使用 std::chrono::duration_cast 将时间转换为毫秒数进行比较，同时在注册事件时也需要使用 std::chrono::milliseconds 类型的时间戳。

以下是修改后的示例代码：

```cpp
#include <iostream>
#include <map>
#include <vector>
#include <chrono>
#include <thread>
#include <algorithm>

// 定义事件类型
enum EventType {
    EVENT_TYPE_A,
    EVENT_TYPE_B,
    EVENT_TYPE_C,
};

// 定义事件结构体
struct Event {
    EventType type;
    std::string data;
    Event(EventType t, const std::string& d) : type(t), data(d) {}
};

// 定义事件处理函数类型
using EventHandler = std::function<void(const Event&)>;

// 定义时间轴类
class TimeLine {
public:
    TimeLine() : currentTime_(std::chrono::milliseconds::zero()) {}

    // 注册事件
    void RegisterEvent(std::chrono::milliseconds time, EventType type, const std::string& data) {
        events_[time].push_back(Event(type, data));
    }

    // 设置时间轴时间
    void SetTime(std::chrono::milliseconds time) {
        if (time < currentTime_) {
            // 时间轴倒退时清空前面的事件
            for (auto it = events_.begin(); it != events_.end();) {
                if (it->first < time) {
                    it = events_.erase(it);
                } else {
                    break;
                }
            }
        }

        currentTime_ = time;
        auto it = events_.find(currentTime_);
        if (it != events_.end()) {
            // 触发当前时刻的所有事件
            for (auto& event : it->second) {
                auto handlerIt = eventHandlers_.find(event.type);
                if (handlerIt != eventHandlers_.end()) {
                    handlerIt->second(event);
                }
            }
        }
    }

    // 注册事件处理函数
    void RegisterEventHandler(EventType type, EventHandler handler) {
        eventHandlers_[type] = handler;
    }

private:
    std::chrono::milliseconds currentTime_;
    std::map<std::chrono::milliseconds, std::vector<Event>> events_;
    std::map<EventType, EventHandler> eventHandlers_;
};

// 示例：打印事件处理结果
void PrintEventHandler(const Event& event) {
    std::cout << "Event type: " << event.type << ", data: " << event.data << std::endl;
}

int main() {
    // 创建时间轴
    TimeLine timeLine;

    // 注册事件处理函数
    timeLine.RegisterEventHandler(EVENT_TYPE_A, PrintEventHandler);
    timeLine.RegisterEventHandler(EVENT_TYPE_B, PrintEventHandler);
    timeLine.RegisterEventHandler(EVENT_TYPE_C, PrintEventHandler);

    // 注册事件
    timeLine.RegisterEvent(std::chrono::milliseconds(1000), EVENT_TYPE_A, "event A at time 1000ms");
    timeLine.RegisterEvent(std::chrono::milliseconds(2000), EVENT_TYPE_B, "event B at time 2000ms");
    timeLine.RegisterEvent(std::chrono::milliseconds(3000), EVENT_TYPE_C, "event C at time 3000ms");
    timeLine.RegisterEvent(std::chrono::milliseconds(3000), EVENT_TYPE_A, "event A2 at time 3000ms");

    // 执行时间轴
    std::chrono::milliseconds timeStep(100);
    std::chrono::milliseconds endTime(std::chrono::milliseconds(4000));
    for (auto t = std::chrono::milliseconds::zero(); t <= endTime; t += timeStep) {
        timeLine.SetTime(std::chrono::duration_cast<std::chrono::milliseconds>(t));
        std::this_thread::sleep_for(timeStep);
    }

    // 反向执行时间轴
    for (auto t = endTime; t >= std::chrono::milliseconds::zero(); t -= timeStep) {
        timeLine.SetTime(std::chrono::duration_cast<std::chrono::milliseconds>(t));
        std::this_thread::sleep_for(timeStep);
    }

    return 0;
}
```

在上述示例代码中，时间轴的时间戳和事件的时间戳都使用了 std::chrono::milliseconds 类型，方便进行毫秒级别的计算。

在执行时间轴时，可以使用 std::chrono::milliseconds 类型的时间步长，逐步调整时间轴时间，并使用 std::chrono::duration_cast 将时间转换为毫秒数来进行比较。

需要注意的是，当使用 std::chrono::milliseconds 类型的时间戳时，需要使用 std::chrono::duration_cast 进行类型转换，这可以使用静态的 cast 函数或者直接调用 duration_cast 函数来实现。
